                if (nodes.length < 2) return
                const opacities = nodes.map((_, i) => Math.round(from + (to - from) * (i / (nodes.length - 1))))
                const opMap: Record<string, number> = {}
                nodes.forEach((n, i) => { opMap[n.uuid] = opacities[i] })
